"use client";

import Image from "next/image";
import Link from "next/link";
import { Browser27 } from "@/components/beste/piece/browser27";
import { Browser28 } from "@/components/beste/piece/browser28";
import { Calendar19 } from "@/components/beste/piece/calendar19";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

type ComponentBackground =
  | { type: "dots" }
  | { type: "none" }
  | { type: "image"; src: string; alt?: string }
  | { type: "video"; src: string; alt?: string };

type RowMedia =
  | { type: "image"; src: string; alt?: string }
  | { type: "video"; src: string; alt?: string }
  | {
      type: "component";
      component: React.ReactNode;
      background?: ComponentBackground;
    };

interface FeatureRow {
  title: string;
  description: string;
  media: RowMedia;
}

interface ButtonItem {
  label: string;
  href?: string;
  variant?:
    | "default"
    | "secondary"
    | "outline"
    | "ghost"
    | "link"
    | "destructive";
}

interface Feature2Props {
  badge?: {
    label: string;
    variant?: "default" | "secondary" | "outline";
  };
  heading?: string;
  description?: string;
  buttons?: ButtonItem[];
  rows?: FeatureRow[];
  className?: string;
}

export const feature2Demo: Feature2Props = {
  badge: { label: "Browser-grade surfaces", variant: "secondary" },
  heading: "Three pieces of the customer-facing toolkit",
  description:
    "Tiny cards that mimic real browser and calendar chrome — drop them into hero shots, marketing pages, and product walkthroughs without rebuilding the surface from scratch.",
  buttons: [{ label: "Read the playbook", href: "https://beste.co/playbook" }],
  rows: [
    {
      title: "Site identity, made glanceable",
      description:
        "A site-info popover that mirrors the lock icon and permission list users already know from their browser. Useful for trust pages, security marketing, and developer docs.",
      media: {
        type: "component",
        component: <Browser27 domain="stripe.com" />,
      },
    },
    {
      title: "Stack the domains your customers ship",
      description:
        "Layered browser windows show the multi-tenant story without diagrams. Drop in the subdomains that matter, the layout adapts to any depth.",
      media: {
        type: "component",
        component: (
          <Browser28
            domains={[
              "customer.beste.co",
              "project.beste.co",
              "jane.beste.co",
              "joe.beste.co",
            ]}
          />
        ),
      },
    },
    {
      title: "Plan the day, not the week",
      description:
        "A vertical day planner with tone-coded blocks. Pulls focus, meetings, and admin into one column so the schedule reads as a single shape.",
      media: {
        type: "component",
        component: (
          <Calendar19
            date="Mon · Apr 27"
            blocks={[
              { start: "09:00", label: "Focus · API refactor", tone: "focus" },
              { start: "10:30", label: "Standup", tone: "meeting" },
              { start: "11:00", label: "Focus · API refactor", tone: "focus" },
              { start: "12:00", label: "Lunch", tone: "break" },
              { start: "13:00", label: "Design review", tone: "meeting" },
              { start: "14:30", label: "Email & admin", tone: "admin" },
            ]}
          />
        ),
      },
    },
  ],
};

export function Feature2({
  badge,
  heading,
  description,
  buttons = [],
  rows = [],
  className,
}: Feature2Props) {
  return (
    <section className={cn("py-16 md:py-24", className)}>
      <div className="mx-auto max-w-6xl px-4 md:px-6">
        <div className="flex max-w-2xl flex-col gap-4">
          {badge && (
            <div>
              <Badge variant={badge.variant ?? "default"}>{badge.label}</Badge>
            </div>
          )}
          {heading && (
            <h2 className="text-2xl font-semibold tracking-tight md:text-4xl">
              {heading}
            </h2>
          )}
          {description && (
            <p className="text-base md:text-lg text-muted-foreground">
              {description}
            </p>
          )}
          {buttons.length > 0 && (
            <div className="mt-2 flex flex-wrap gap-3">
              {buttons.map((button, index) => (
                <Button
                  key={index}
                  variant={button.variant ?? "default"}
                  asChild
                >
                  <Link href={button.href ?? "#"}>{button.label}</Link>
                </Button>
              ))}
            </div>
          )}
        </div>

        <div className="mt-16 flex flex-col gap-10 md:gap-16">
          {rows.map((row, index) => {
            const reverse = index % 2 === 1;
            return (
              <div
                key={index}
                className={cn(
                  "flex flex-col gap-6 md:items-center md:gap-10",
                  reverse ? "md:flex-row-reverse" : "md:flex-row"
                )}
              >
                <div className="md:w-1/2">
                  <RowMediaSurface media={row.media} />
                </div>
                <div className="flex flex-col gap-3 md:w-1/2">
                  <h3 className="text-lg font-semibold md:text-2xl">
                    {row.title}
                  </h3>
                  <p className="text-sm text-muted-foreground md:text-base">
                    {row.description}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

function RowMediaSurface({ media }: { media: RowMedia }) {
  const componentBackground =
    media.type === "component" ? media.background ?? { type: "dots" } : null;
  const showDots = componentBackground?.type === "dots";

  return (
    <div
      className="relative flex aspect-video items-center justify-center overflow-hidden rounded-md border bg-muted/30"
      style={
        showDots
          ? {
              backgroundImage:
                "radial-gradient(circle, var(--border) 1px, transparent 1px)",
              backgroundSize: "16px 16px",
            }
          : undefined
      }
    >
      {componentBackground?.type === "image" && (
        <Image
          src={componentBackground.src}
          alt={componentBackground.alt ?? ""}
          fill
          className="object-cover"
          aria-hidden="true"
        />
      )}
      {componentBackground?.type === "video" && (
        <video
          src={componentBackground.src}
          autoPlay
          loop
          muted
          playsInline
          className="absolute inset-0 size-full object-cover"
        />
      )}

      {media.type === "video" ? (
        <video
          src={media.src}
          autoPlay
          loop
          muted
          playsInline
          aria-label={media.alt}
          className="size-full object-cover"
        />
      ) : media.type === "image" ? (
        <Image
          src={media.src}
          alt={media.alt ?? ""}
          fill
          className="object-cover"
        />
      ) : (
        <div className="relative flex size-full items-center justify-center">
          {media.component}
        </div>
      )}
    </div>
  );
}

"use client";

import { Camera, Lock, MapPin, Mic, type LucideIcon } from "lucide-react";
import { cn } from "@/lib/utils";

type PermissionIcon = "camera" | "location" | "mic" | "lock";

interface Permission {
  icon?: PermissionIcon;
  label: string;
  granted?: boolean;
  grantedLabel?: string;
  deniedLabel?: string;
}

interface Browser27Props {
  domain?: string;
  connectionLabel?: string;
  permissions?: Permission[];
  defaultGrantedLabel?: string;
  defaultDeniedLabel?: string;
  className?: string;
}

const ICONS: Record<PermissionIcon, LucideIcon> = {
  camera: Camera,
  location: MapPin,
  mic: Mic,
  lock: Lock,
};

export const browser27Demo: Browser27Props = {
  domain: "stripe.com",
  connectionLabel: "Connection is secure",
  permissions: [
    { icon: "camera", label: "Camera", granted: true },
    { icon: "location", label: "Location", granted: false },
  ],
  defaultGrantedLabel: "Allowed",
  defaultDeniedLabel: "Ask",
};

export function Browser27({
  domain = "example.com",
  connectionLabel = "Connection is secure",
  permissions = [],
  defaultGrantedLabel = "Allowed",
  defaultDeniedLabel = "Ask",
  className,
}: Browser27Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-72 flex-col gap-2 rounded-lg border border-border bg-card p-3 shadow-md">
        <div className="flex items-center gap-2">
          <div className="flex size-7 shrink-0 items-center justify-center rounded-full bg-emerald-100 text-emerald-600 dark:bg-emerald-950 dark:text-emerald-400">
            <Lock className="size-3.5" aria-hidden="true" />
          </div>
          <div className="flex min-w-0 flex-1 flex-col">
            <span className="truncate text-sm font-semibold text-card-foreground">
              {domain}
            </span>
            <span className="text-xs text-emerald-600 dark:text-emerald-400">
              {connectionLabel}
            </span>
          </div>
        </div>
        {permissions.length > 0 && (
          <div className="flex flex-col gap-1 border-t border-border pt-2 text-xs">
            {permissions.map((p, idx) => {
              const Icon = ICONS[p.icon ?? "lock"];
              const granted = p.granted ?? false;
              return (
                <div
                  key={`${p.label}-${idx}`}
                  className="flex items-center justify-between gap-2"
                >
                  <div className="flex items-center gap-2 text-card-foreground">
                    <Icon
                      className="size-3.5 text-muted-foreground"
                      aria-hidden="true"
                    />
                    <span>{p.label}</span>
                  </div>
                  <span
                    className={cn(
                      "font-semibold",
                      granted
                        ? "text-emerald-600 dark:text-emerald-400"
                        : "text-muted-foreground"
                    )}
                  >
                    {granted
                      ? p.grantedLabel ?? defaultGrantedLabel
                      : p.deniedLabel ?? defaultDeniedLabel}
                  </span>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { Lock } from "lucide-react";
import { cn } from "@/lib/utils";

interface Browser28Props {
  domains?: string[];
  className?: string;
}

export const browser28Demo: Browser28Props = {
  domains: [
    "customer.beste.co",
    "project.beste.co",
    "jane.beste.co",
    "joe.beste.co",
  ],
};

const LAYERS = [
  {
    radius: 8,
    py: 8,
    px: 12,
    barH: 16,
    fontSize: 12,
    buttonSize: 8,
    buttonGap: 4,
    iconSize: 12.5,
  },
  {
    radius: 7,
    py: 6.75,
    px: 10,
    barH: 14,
    fontSize: 9.5,
    buttonSize: 7,
    buttonGap: 4,
    iconSize: 10.5,
  },
  {
    radius: 6,
    py: 6,
    px: 8.75,
    barH: 12,
    fontSize: 7.75,
    buttonSize: 6,
    buttonGap: 2,
    iconSize: 9,
  },
  {
    radius: 5,
    py: 5,
    px: 7.5,
    barH: 10,
    fontSize: 6,
    buttonSize: 5,
    buttonGap: 2,
    iconSize: 7,
  },
];

const TRAFFIC = ["bg-rose-400", "bg-amber-400", "bg-emerald-400"];

export function Browser28({ domains = [], className }: Browser28Props) {
  const list = domains.slice(0, LAYERS.length);
  const label = `Stacked browser windows for ${list.join(", ")}`;

  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div
        aria-label={label}
        className="mx-auto flex h-full w-11/12 max-w-80 flex-col-reverse items-center justify-center"
      >
        {list.map((domain, i) => {
          const l = LAYERS[i]!;
          return (
            <div
              key={i}
              aria-hidden="true"
              className="relative flex w-full items-center border border-border bg-card shadow-sm"
              style={{
                width: `calc(100% - ${32 * i}px)`,
                borderRadius: `${l.radius}px ${l.radius}px 0 0`,
                padding: `${l.py}px ${l.px}px`,
                zIndex: 10 - i,
                opacity: 1 - i * 0.1,
                marginBottom: -2,
              }}
            >
              <div
                className="flex items-center"
                style={{ gap: `${l.buttonGap}px` }}
              >
                {[0, 1, 2].map((d) => (
                  <span
                    key={d}
                    className={cn(
                      "shrink-0 rounded-full",
                      i === 0 ? TRAFFIC[d] : "bg-muted-foreground/30"
                    )}
                    style={{
                      width: `${l.buttonSize}px`,
                      height: `${l.buttonSize}px`,
                    }}
                    aria-hidden="true"
                  />
                ))}
              </div>
              <div
                className="mx-auto flex items-center justify-center gap-1 rounded-full text-card-foreground"
                style={{
                  height: `${l.barH}px`,
                  fontSize: `${l.fontSize}px`,
                }}
              >
                <Lock
                  className="text-muted-foreground"
                  style={{
                    width: `${l.iconSize}px`,
                    height: `${l.iconSize}px`,
                  }}
                  aria-hidden="true"
                />
                <span className="truncate">{domain}</span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";

interface Block {
  start: string;
  label: string;
  tone: "focus" | "meeting" | "break" | "admin";
}

interface Calendar19Props {
  date?: string;
  blocks?: Block[];
  className?: string;
}

const toneClasses: Record<Block["tone"], string> = {
  focus: "bg-sky-500/15 text-sky-700 dark:text-sky-300",
  meeting: "bg-violet-500/15 text-violet-700 dark:text-violet-300",
  break: "bg-emerald-500/15 text-emerald-700 dark:text-emerald-300",
  admin: "bg-amber-500/15 text-amber-700 dark:text-amber-300",
};

export const calendar19Demo: Calendar19Props = {
  date: "Mon · Apr 27",
  blocks: [
    { start: "09:00", label: "Focus · API refactor", tone: "focus" },
    { start: "10:30", label: "Standup", tone: "meeting" },
    { start: "11:00", label: "Focus · API refactor", tone: "focus" },
    { start: "12:00", label: "Lunch", tone: "break" },
    { start: "13:00", label: "Design review", tone: "meeting" },
    { start: "14:30", label: "Email & admin", tone: "admin" },
  ],
};

export function Calendar19({
  date,
  blocks = [],
  className,
}: Calendar19Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-80 flex-col gap-2 rounded-xl border border-border bg-card p-3 shadow-sm">
        {date && (
          <span className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
            {date}
          </span>
        )}
        <div className="flex flex-col gap-1.5">
          {blocks.map((b, idx) => (
            <div key={idx} className="flex items-center gap-3">
              <span className="w-12 shrink-0 text-right font-mono text-xs text-muted-foreground">
                {b.start}
              </span>
              <div
                className={cn(
                  "flex min-h-8 flex-1 items-center rounded-md px-2.5 py-1",
                  toneClasses[b.tone]
                )}
              >
                <span className="text-sm font-medium text-card-foreground">
                  {b.label}
                </span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
